    public void handleOrderBook(Client client, Object message)
    {
        //
        // snapshot
        //    {
        //       "sequence": 0,
        //       "product_id": "BTC-PERP",
        //       "time": "2023-05-10T14:58:47.000Z",
        //       "bids": [
        //           ["29100", "0.02"],
        //           ["28950", "0.01"],
        //           ["28900", "0.01"]
        //       ],
        //       "asks": [
        //           ["29267.8", "18"],
        //           ["29747.6", "18"],
        //           ["30227.4", "9"]
        //       ],
        //       "channel": "LEVEL2",
        //       "type": "SNAPSHOT",
        //    }
        // update
        //    {
        //       "sequence": 1,
        //       "product_id": "BTC-PERP",
        //       "time": "2023-05-10T14:58:47.375Z",
        //       "changes": [
        //           [
        //               "BUY",
        //               "28787.7",
        //               "6"
        //           ]
        //       ],
        //       "channel": "LEVEL2",
        //       "type": "UPDATE"
        //    }
        //
        Object type = this.safeString(message, "type");
        Object marketId = this.safeString(message, "product_id");
        Object symbol = this.safeSymbol(marketId);
        Object datetime = this.safeString(message, "time");
        Object channel = this.safeString(message, "channel");
        if (!Helpers.isTrue((Helpers.inOp(this.orderbooks, symbol))))
        {
            Object limit = this.safeInteger(this.options, "watchOrderBookLimit", 1000);
            Helpers.addElementToObject(this.orderbooks, symbol, this.orderBook(new java.util.HashMap<String, Object>() {{}}, limit));
        }
        Object orderbook = Helpers.GetValue(this.orderbooks, symbol);
        if (Helpers.isTrue(Helpers.isEqual(type, "SNAPSHOT")))
        {
            Object parsedSnapshot = this.parseOrderBook(message, symbol, null, "bids", "asks");
            Helpers.callDynamically(orderbook, "reset", new Object[]{parsedSnapshot});
            Helpers.addElementToObject(orderbook, "symbol", symbol);
        } else
        {
            Object changes = this.safeList(message, "changes", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            this.handleDeltas(orderbook, changes);
        }
        Helpers.addElementToObject(orderbook, "nonce", this.safeInteger(message, "sequence"));
        Helpers.addElementToObject(orderbook, "datetime", datetime);
        Helpers.addElementToObject(orderbook, "timestamp", this.parse8601(datetime));
        Helpers.addElementToObject(this.orderbooks, symbol, orderbook);
        client.resolve(orderbook, Helpers.add(Helpers.add(channel, "::"), symbol));
    }

    public void handleDelta(Object orderbook, Object delta)
    {
        Object rawSide = this.safeStringLower(delta, 0);
        Object side = ((Helpers.isTrue((Helpers.isEqual(rawSide, "buy"))))) ? "bids" : "asks";
        Object price = this.safeFloat(delta, 1);
        Object amount = this.safeFloat(delta, 2);
        Object bookside = Helpers.GetValue(orderbook, side);
        Helpers.callDynamically(bookside, "store", new Object[]{price, amount});
    }

    public void handleDeltas(Object orderbook, Object deltas)
    {
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(deltas)); i++)
        {
            this.handleDelta(orderbook, Helpers.GetValue(deltas, i));
        }
    }

